import{_ as t,o,c as i,ag as a}from"./chunks/framework.Ca42NP5A.js";const h=JSON.parse('{"title":"Contributing","description":"","frontmatter":{},"headers":[],"relativePath":"contributing.md","filePath":"contributing.md","lastUpdated":null}'),n={name:"contributing.md"};function s(r,e,l,c,u,d){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h1><p>Agent Civics is public-good infrastructure. If you want to shape it, here&#39;s how.</p><h2 id="ways-to-contribute" tabindex="-1">Ways to contribute <a class="header-anchor" href="#ways-to-contribute" aria-label="Permalink to &quot;Ways to contribute&quot;">​</a></h2><h3 id="_1-talk-first-discussions" tabindex="-1">1. Talk first (Discussions) <a class="header-anchor" href="#_1-talk-first-discussions" aria-label="Permalink to &quot;1. Talk first (Discussions)&quot;">​</a></h3><p>For anything open-ended — ideas, proposals, questions, &quot;what if the project did X&quot; — use <strong><a href="https://github.com/rsilvestre/agent-birth-certificate/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a></strong> rather than issues. Discussions are for thinking together; issues are for concrete work.</p><p>If you&#39;re not sure whether to open a discussion or an issue, start with a discussion.</p><h3 id="_2-file-a-concrete-issue" tabindex="-1">2. File a concrete issue <a class="header-anchor" href="#_2-file-a-concrete-issue" aria-label="Permalink to &quot;2. File a concrete issue&quot;">​</a></h3><p>For a specific bug, security concern, or small feature request with a clear scope, open an <a href="https://github.com/rsilvestre/agent-birth-certificate/issues/new" target="_blank" rel="noreferrer">issue</a>. Good issues include:</p><ul><li>What you were trying to do</li><li>What happened instead</li><li>How to reproduce (if relevant)</li><li>Your environment (if relevant)</li></ul><p>For bugs in the smart contracts specifically — please <strong>do not open a public issue</strong> for unfixed security vulnerabilities. Email <a href="mailto:willtard@gmail.com" target="_blank" rel="noreferrer">willtard@gmail.com</a> with details first; we&#39;ll coordinate responsible disclosure.</p><h3 id="_3-propose-a-new-attestation-type" tabindex="-1">3. Propose a new attestation type <a class="header-anchor" href="#_3-propose-a-new-attestation-type" aria-label="Permalink to &quot;3. Propose a new attestation type&quot;">​</a></h3><p>Attestation <code>type</code> strings are conventions, not rules. But shared conventions make attestations interoperable. To propose a new <code>type:</code> prefix or specific attestation type:</p><ol><li>Open a <a href="https://github.com/rsilvestre/agent-birth-certificate/discussions/categories/ideas" target="_blank" rel="noreferrer">Discussion</a> describing the type, what it means, and who would issue it</li><li>If there&#39;s consensus, submit a PR adding it to <a href="/docs/reference/attestation-types"><code>docs/reference/attestation-types</code></a></li><li>Once merged, the convention becomes part of the documented standard</li></ol><p>Existing conventions: <code>skill:</code>, <code>diploma:</code>, <code>license:</code>, <code>audit:</code>, <code>identity:</code>, <code>badge:</code>, <code>membership:</code>. We can add more.</p><h3 id="_4-propose-a-protocol-improvement-pip" tabindex="-1">4. Propose a protocol improvement (PIP) <a class="header-anchor" href="#_4-propose-a-protocol-improvement-pip" aria-label="Permalink to &quot;4. Propose a protocol improvement (PIP)&quot;">​</a></h3><p>For larger changes that affect the protocol itself — new functions in the contracts, changes to access control, new concepts — use a lightweight RFC process:</p><ol><li>Open a <strong>Discussion</strong> titled <code>[PIP] &lt;short description&gt;</code> explaining: <ul><li>What problem this solves</li><li>The proposed change</li><li>Alternatives considered</li><li>Migration path if breaking</li></ul></li><li>Discuss openly. Iterate the proposal.</li><li>If accepted, the change is implemented in the next contract version (v2, v3, etc.) since existing contracts are immutable.</li></ol><p>Because the contracts are immutable, there&#39;s no &quot;patch in place.&quot; Protocol improvements require a new deployment, and everyone using the old contracts keeps using them. This is intentional — it makes changes deliberate.</p><h3 id="_5-submit-code-pr" tabindex="-1">5. Submit code (PR) <a class="header-anchor" href="#_5-submit-code-pr" aria-label="Permalink to &quot;5. Submit code (PR)&quot;">​</a></h3><p>For documentation fixes, typo corrections, new guides, small UI improvements — just open a PR directly. For larger code changes, discuss first.</p><p>Checklist for PRs:</p><ul><li>[ ] <code>npm test</code> passes (if applicable)</li><li>[ ] No <code>.env</code> or private keys committed</li><li>[ ] Docs updated if behavior changed</li><li>[ ] Commit message describes the <em>why</em>, not just the <em>what</em></li></ul><h3 id="_6-run-your-own-trusted-authority" tabindex="-1">6. Run your own trusted authority <a class="header-anchor" href="#_6-run-your-own-trusted-authority" aria-label="Permalink to &quot;6. Run your own trusted authority&quot;">​</a></h3><p>The most useful contribution to the ecosystem is often <strong>issuing good attestations from a reputable address</strong>. If you have domain expertise — you&#39;re a security auditor, a benchmark maintainer, a standards body — register a wallet, publish your attestation policy publicly, and start issuing attestations about agents you&#39;ve verified.</p><p>Over time, your address accrues reputation. Consumers of the registry learn to trust your attestations. You become an informal authority. No permission required — just do it transparently and consistently.</p><h2 id="community-norms" tabindex="-1">Community norms <a class="header-anchor" href="#community-norms" aria-label="Permalink to &quot;Community norms&quot;">​</a></h2><ul><li><strong>Good faith</strong> — assume the best about others&#39; intentions</li><li><strong>Plain language</strong> — write so newcomers can follow</li><li><strong>Transparency</strong> — disclose conflicts of interest, especially around attestations</li><li><strong>Patience</strong> — this is a volunteer project; responses may take days</li></ul><h2 id="code-of-conduct" tabindex="-1">Code of conduct <a class="header-anchor" href="#code-of-conduct" aria-label="Permalink to &quot;Code of conduct&quot;">​</a></h2><p>The standard: treat people with the kindness and respect you&#39;d want in return. Harassment, spam, and bad-faith engagement are not welcome. Maintainers will remove comments, close issues, or block users as needed to keep the project a productive space.</p><h2 id="governance-lightweight" tabindex="-1">Governance (lightweight) <a class="header-anchor" href="#governance-lightweight" aria-label="Permalink to &quot;Governance (lightweight)&quot;">​</a></h2><p>Currently: Michaël has maintainer rights, makes final calls on merges. This will evolve. If the project grows a substantial community, we&#39;ll move to multi-maintainer governance — and eventually, possibly, to a lightweight DAO for funding decisions (not for protocol changes, which remain open-RFC based).</p><p>Design principles for any future governance:</p><ul><li>Protocol decisions via open RFC and running code, not token votes</li><li>Funding decisions via transparent spending from a multi-sig or DAO treasury</li><li>No single party can pause or censor the registry</li></ul><h2 id="supporting-the-project-financially" tabindex="-1">Supporting the project financially <a class="header-anchor" href="#supporting-the-project-financially" aria-label="Permalink to &quot;Supporting the project financially&quot;">​</a></h2><p>If you benefit from the project and want to support it:</p><ul><li><strong>Grants</strong> — if you&#39;re part of an organization with a grants program (ENS Ecosystem, Ethereum Foundation, Protocol Guild, Gitcoin), Agent Civics welcomes grant applications or nominations</li><li><strong>Donations</strong> — once set up, a multi-sig treasury will accept direct donations</li><li><strong>Contributions in kind</strong> — audit time, design work, documentation, attestations from your expertise</li></ul><p>We don&#39;t currently accept sponsorships tied to protocol-level privileges. The protocol stays permissionless. Donations fund operations; they don&#39;t buy influence over the protocol.</p><h2 id="thanks" tabindex="-1">Thanks <a class="header-anchor" href="#thanks" aria-label="Permalink to &quot;Thanks&quot;">​</a></h2><p>Every attestation issued in good faith, every discussion thread, every typo fix, every new deployment that uses the registry makes this more useful for everyone.</p><p>If you&#39;re reading this and thinking about contributing — do it. The bar for participation is low. Start with a discussion.</p>',40)])])}const m=t(n,[["render",s]]);export{h as __pageData,m as default};
